# TECH_DEBT(TD-005): O(n^2) complexity here.
# Should use a hash map for O(n). Low priority until data > 10k items.
# Severity: 2, Interest: ~15 min/week on current data size.
def find_duplicates(items: list) -> list:
    duplicates = []
    for i, item in enumerate(items):
        for j, other in enumerate(items):
            if i != j and item == other and item not in duplicates:
                duplicates.append(item)
    return duplicates
